properties.entry:

insert ignore into ip_dim (ip_key, ipv4, ipv6) values(
    -2147483648, 0, 0
);


insert ignore into date_dim(date) (
    select distinct date(t1.poll_time)
    from tplink_deco_device_info_stg t1
    left join date_dim dd on date(t1.poll_time) = dd.date
    where dd.date_key is null
);


create temporary table  tmp_ap_dim_normalize (
    ap_mac bigint,
    ap_name varchar(255)
);


create temporary table  tmp_ip_dim_normalize (
    ipv4 int not null
);
